-- ----------------------------
-- Table structure for auth_login_record
-- ----------------------------
DROP TABLE IF EXISTS `auth_login_record`;
CREATE TABLE `auth_login_record` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键编号',
  `tenant_id` bigint NOT NULL COMMENT '租户编号',
  `user_id` bigint DEFAULT NULL COMMENT '用户编号',
  `username` varchar(64) NOT NULL COMMENT '登录账号',
  `user_type` varchar(32) NOT NULL DEFAULT '' COMMENT '用户类型',
  `login_status` varchar(32) NOT NULL COMMENT '登录状态',
  `failure_reason` varchar(256) NOT NULL DEFAULT '' COMMENT '失败原因',
  `token_digest` varchar(64) NOT NULL DEFAULT '' COMMENT '令牌摘要',
  `login_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '登录时间',
  `logout_time` datetime DEFAULT NULL COMMENT '退出时间',
  `client_ip` varchar(64) NOT NULL DEFAULT '' COMMENT '客户端 IP',
  `user_agent` varchar(512) NOT NULL DEFAULT '' COMMENT '客户端标识',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人编号',
  `update_by` bigint DEFAULT NULL COMMENT '更新人编号',
  `deleted` smallint NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
  PRIMARY KEY (`id`),
  KEY `idx_auth_login_record_tenant_username` (`tenant_id`,`username`),
  KEY `idx_auth_login_record_login_time` (`login_time` DESC),
  KEY `idx_auth_login_record_token_digest` (`token_digest`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='认证登录记录表';

-- ----------------------------
-- Records of auth_login_record
-- ----------------------------
