DROP TABLE IF EXISTS `pat_patient`;
CREATE TABLE `pat_patient` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键编号',
  `tenant_id` bigint NOT NULL COMMENT '租户编号',
  `user_id` varchar(34) NOT NULL COMMENT '关联用户编号（关联sys_user.user_id）',
  `name` varchar(64) NOT NULL COMMENT '兼容旧表患者姓名',
  `patient_name` varchar(64) NOT NULL DEFAULT '' COMMENT '患者姓名',
  `phone` varchar(32) DEFAULT NULL COMMENT '联系电话',
  `gender` varchar(16) NOT NULL DEFAULT '' COMMENT '患者性别',
  `age` int NOT NULL DEFAULT '0' COMMENT '患者年龄',
  `risk_level` varchar(32) NOT NULL DEFAULT '低风险' COMMENT '风险等级',
  `id_card` varchar(32) DEFAULT NULL COMMENT '身份证号',
  `birthday` date DEFAULT NULL COMMENT '出生日期',
  `address` varchar(512) DEFAULT NULL COMMENT '联系地址',
  `last_visit` date DEFAULT NULL COMMENT '最近就诊日期',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人编号',
  `update_by` bigint DEFAULT NULL COMMENT '更新人编号',
  `deleted` smallint NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
  PRIMARY KEY (`id`),
  KEY `idx_pat_patient_user` (`tenant_id`,`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='患者档案表';

-- ----------------------------
-- Records of pat_patient
-- ----------------------------
BEGIN;
COMMIT;


