-- ----------------------------
-- Table structure for doc_department
-- ----------------------------
DROP TABLE IF EXISTS `doc_department`;
CREATE TABLE `doc_department` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键编号',
  `dept_id` bigint DEFAULT NULL COMMENT '系统部门编号，关联 sys_dept.id',
  `tenant_id` bigint NOT NULL COMMENT '租户编号',
  `name` varchar(128) NOT NULL COMMENT '兼容旧表科室名称',
  `department_name` varchar(64) NOT NULL DEFAULT '' COMMENT '科室名称',
  `doctor_count` int NOT NULL DEFAULT '0' COMMENT '医生数量',
  `queue_desc` varchar(64) NOT NULL DEFAULT '' COMMENT '排队描述',
  `parent_id` bigint NOT NULL DEFAULT '0' COMMENT '父级科室编号',
  `sort` int NOT NULL DEFAULT '0' COMMENT '科室排序',
  `status` varchar(32) NOT NULL DEFAULT '0' COMMENT '科室状态',
  `description` varchar(512) DEFAULT NULL COMMENT '科室说明',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人编号',
  `update_by` bigint DEFAULT NULL COMMENT '更新人编号',
  `deleted` smallint NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_doc_department_dept_active` (`tenant_id`,`dept_id`,`deleted`)
) ENGINE=InnoDB AUTO_INCREMENT=35 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='科室扩展表';

