BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for doc_doctor
-- ----------------------------
DROP TABLE IF EXISTS `doc_doctor`;
CREATE TABLE `doc_doctor` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键编号',
  `user_id` varchar(34) NOT NULL COMMENT '关联用户编号（关联sys_user.user_id）',
  `tenant_id` bigint NOT NULL COMMENT '租户编号',
  `name` varchar(64) NOT NULL COMMENT '医生姓名',
  `doctor_name` varchar(64) NOT NULL DEFAULT '' COMMENT '医生姓名',
  `avatar` varchar(512) DEFAULT NULL COMMENT '头像地址',
  `title` varchar(64) DEFAULT NULL COMMENT '医生职称',
  `department` varchar(64) NOT NULL DEFAULT '' COMMENT '所属科室',
  `specialty` varchar(512) DEFAULT NULL COMMENT '擅长方向',
  `introduction` text COMMENT '医生简介',
  `consult_fee` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '问诊费用',
  `consult_status` varchar(32) NOT NULL DEFAULT 'OFFLINE' COMMENT '接诊状态',
  `rating` decimal(3,2) NOT NULL DEFAULT '0.00' COMMENT '评分',
  `status` varchar(32) NOT NULL DEFAULT '接诊中' COMMENT '展示状态',
  `schedule_desc` varchar(128) NOT NULL DEFAULT '今日暂无排班' COMMENT '排班描述',
  `patient_count` int NOT NULL DEFAULT '0' COMMENT '当前接诊患者数',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人编号',
  `update_by` bigint DEFAULT NULL COMMENT '更新人编号',
  `deleted` smallint NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
  PRIMARY KEY (`id`),
  KEY `idx_doc_doctor_user` (`tenant_id`,`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='医生信息表';

-- ----------------------------
-- Records of doc_doctor
-- ----------------------------
BEGIN;
COMMIT;

