COMMIT;

-- ----------------------------
-- Table structure for doc_schedule
-- ----------------------------
DROP TABLE IF EXISTS `doc_schedule`;
CREATE TABLE `doc_schedule` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键编号',
  `doctor_id` bigint NOT NULL COMMENT '医生编号',
  `dept_id` bigint DEFAULT NULL COMMENT '科室编号',
  `department_id` bigint DEFAULT NULL COMMENT '科室编号',
  `tenant_id` bigint NOT NULL COMMENT '租户编号',
  `slot` varchar(128) NOT NULL DEFAULT '' COMMENT '出诊时段',
  `schedule_date` date NOT NULL COMMENT '排班日期',
  `time_slot` varchar(64) NOT NULL COMMENT '排班时间段',
  `total_number` int NOT NULL DEFAULT '0' COMMENT '总号源数量',
  `remain_number` int NOT NULL DEFAULT '0' COMMENT '剩余号源数量',
  `status` smallint NOT NULL DEFAULT '1' COMMENT '排班状态',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人编号',
  `update_by` bigint DEFAULT NULL COMMENT '更新人编号',
  `deleted` smallint NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='医生排班表';

