-- ----------------------------
-- Table structure for con_consult
-- ----------------------------
DROP TABLE IF EXISTS `con_consult`;
CREATE TABLE `con_consult` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键编号',
  `tenant_id` bigint NOT NULL COMMENT '租户编号',
  `patient_id` bigint NOT NULL COMMENT '患者编号',
  `doctor_id` bigint NOT NULL COMMENT '医生编号',
  `patient_name` varchar(100) NOT NULL DEFAULT '' COMMENT '患者姓名',
  `doctor_name` varchar(100) NOT NULL DEFAULT '' COMMENT '医生姓名',
  `channel` varchar(32) NOT NULL DEFAULT '' COMMENT '问诊渠道',
  `consult_type` varchar(32) NOT NULL COMMENT '问诊类型',
  `consult_no` varchar(64) NOT NULL DEFAULT '' COMMENT '问诊单号',
  `status` smallint NOT NULL DEFAULT '0' COMMENT '问诊状态',
  `fee_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '问诊费用',
  `duration_limit` int NOT NULL DEFAULT '0' COMMENT '问诊时长上限分钟',
  `remaining_seconds` int NOT NULL DEFAULT '0' COMMENT '剩余问诊秒数',
  `updated_at` varchar(32) NOT NULL DEFAULT '' COMMENT '前端展示更新时间',
  `start_time` datetime DEFAULT NULL COMMENT '接单开始时间',
  `end_time` datetime DEFAULT NULL COMMENT '问诊结束时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_by` bigint DEFAULT NULL COMMENT '创建人编号',
  `update_by` bigint DEFAULT NULL COMMENT '更新人编号',
  `deleted` smallint NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='问诊单表';

